questions.question:
The output of executing the following C program is _____________.

#include <stdio.h>
int total(int v) {
    static int count = 0;
    while (v) {
        count += v & 1;
        v >>= 1;
    }
    return count;
}
void main() {
    static int x = 0;
    x += total(5);
    x += total(12);
    x += total(10);
    printf("%d", x);
}

A. 8  B. 12  C. 13  D. 5

Consider the following C program.

#include <stdio.h>
int main() {
    int m = 10;
    int n, n1;
    n = ++m;
    n1 = m++;
    n--;
    --n1;
    n -= n1;
    printf("%d", n);
    return 0;
}

The output of the program is _______.

A. -1  B. 0  C. 1  D. 2

Consider the following C code. Assume that unsigned long int type length is 64 bits.

unsigned long int fun(unsigned long int n) {
    unsigned long int i, j = 0, sum = 0;
    for (i = n; i > 1; i = i / 2)
        j++;
    for (; j > 1; j = j / 2)
        sum++;
    return sum;
}

The value returned when we call fun() with the input 2^31 is:

A. 4  B. 5  C. 6  D. 40
